#include "ScalarConverter.hpp"

int main(int argc, char *argv[]) {
	if (argc != 2) {
		std::cout << "Usage: ./convert [literal]" << std::endl;
		return (1);
	}

	const char* test_cases[] = {
		"'a'", "'Z'", "' '", "'~'", " ", "", "R",
		"0", "-42", "42", "2147483647", "-2147483648",
		"0.0f", "-4.2f", "4.2f", "123.456f",
		"-inff", "+inff", "nanf",
		"340282346638528859811704183484516925440.0f",	// float max
		"-340282346638528859811704183484516925440.0f",	// float min
		"0.0", "-4.2", "4.2", "123.456",
		"-inf", "+inf", "nan",
		".0", // double max
		"-.0", // double min
		"42.0f", "42.0", "42", "'*'",
		"0.000000000000000000000000000000000000000000001f",
		"0.000000000000000000000000000000000000000000001",
		"invalid", "123abc", "", "123.456.789",
		"123f",		// missing decimal
		"inff",		// invalid special float
		"inf",		// invalid special double
		"123..456f"
	};

	if (std::string(argv[1]) == "all")
	{
		for (size_t i = 0; i < sizeof(test_cases)/sizeof(test_cases[0]); ++i)
		{
			std::cout << "\n\033[1;36mTEST CASE [" << i << "]: " << test_cases[i] << "\033[0m" << std::endl;
			ScalarConverter::convert(const_cast<char*>(test_cases[i]));
		}
	}
	else
	{
		ScalarConverter::convert(argv[1]);
	}

	return (0);
}
